/// <reference path="../../../node_modules/jibo/typings/index.d.ts" />
import jibo = require('jibo');
import './utils/stats';
import DiagnosticsSkill from './DiagnosticsSkill';
import log, {loadLogConfig} from './log';

// Create the skill
const skill:DiagnosticsSkill = new DiagnosticsSkill();

// Initialize jibo and start the skill
jibo.init({ display: 'face'}, () => {
    loadLogConfig();

    jibo.action.configure({ orientToHJ: false });   // no HJ turning

    jibo.expression.setAttentionMode(jibo.expression.AttentionMode.OFF)         // no attention
    .then( () => {
        return jibo.expression.indexRobot();        // index robot
    })
    .then( () => {
        skill.start();                              // start skill
    })
    .catch( (error) => {
        log.error(error);
        skill.start();                              // if err, start it anyway?
    });
});