import BaseTest from '../BaseTest';
import jibo = require('jibo');
import path = require('path');
import $ from '../utils/querySelector';
import {PromiseUtils as Async} from 'jibo-cai-utils';

let colors:[number, number, number][] = [
    [1, 1, 1],
    [1, 0, 0],
    [1, 77/255, 0],
    [1, 1, 0],
    [72/255, 1, 0],
    [0, 234/255, 1],
    [0, 17/255, 1],
    [98/255, 0, 1],
    [1, 0, 1],
    [1, 1, 1]
];
/*
* LED diagnostic test
* */
class LEDTest extends BaseTest {

    public exiting:boolean = false;

    constructor(testName:string) {
        super(testName);
    }

    async enter() {
        super.enter();

        await jibo.expression.blink();
        await jibo.expression.centerRobot({centerGlobally: true});

        $('#test-label').innerHTML = 'Pretty colors';
        this.exiting = false;
        this.laodAndPlay();
    }

    async laodAndPlay() {
        for(let i = 0; i < colors.length; i++) {
            jibo.expression.setLEDColor(colors[i]);
            await Async.promisify<void>(cb => setTimeout(cb, 500));
        }
        if (!this.exiting) {
            this.laodAndPlay(); // loop if we are not exiting test
        }
    }

    exit() {
        super.exit();

        $('#test-label').innerHTML = '';
        this.exiting = true;
        jibo.expression.setLEDColor([0,0,0]);
    }
}

export default LEDTest;
