import BaseTest from '../BaseTest';
import jibo = require('jibo');
import $ from '../utils/querySelector';

const audioTracking = require('../behaviors/audio-tracking');

/*
* LPS audio tracking diagnostic test
* */
class AudioTrackingTest extends BaseTest {

    public root:any;

    constructor(testName:string) {
        super(testName);
        this.root = jibo.bt.create(audioTracking);
    }

    async enter() {
        super.enter();

        $('#test-label').innerHTML = 'Say something and I\'ll follow your voice!';
        this.root.start();
    }

    exit() {
        super.exit();
        
        $('#test-label').innerHTML = '';
        this.root.stop();
    }

    update() {
        this.root.update();
    }
}

export default AudioTrackingTest;
