import jibo = require('jibo');
import BaseTest from '../BaseTest';
import $ from '../utils/querySelector';

const asrTest = require('../behaviors/asr-test');

/*
* ASR diagnostic test
* */
class ASRTest extends BaseTest {

    public root:any;
    

    constructor(testName:string) {
        super(testName);
        const blackboard = {
            setLabel: this.setLabel
        };
        this.root = jibo.bt.create(asrTest, {blackboard: blackboard});
    }

    setLabel(label) {
        $('#test-label').innerHTML = label;
    }

    async enter() {
        super.enter();

        this.root.start();
    }

    exit() {
        super.exit();

        this.root.stop();
        $('#test-label').innerHTML = '';
    }

    update() {
        this.root.update();
    }
}

export default ASRTest;