import BaseTest from '../BaseTest';
import {media} from 'jibo';
import $ from '../utils/querySelector';

/*
* Take a photo diagnostic test
* */
class PhotoTest extends BaseTest {

    public running:boolean;
    public autoRun:boolean;
    public myIntervalId:any;
    public autoRunAttempts:number;
    public autoRunSuccesses:number;

    constructor(testName:string) {
        super(testName);
        this.running = false;

        this.autoRun = true;    // turn on if you want it to take a picture every 3 seconds 20 times
        this.myIntervalId = undefined;
        this.autoRunAttempts = 0;
        this.autoRunSuccesses = 0;
    }

    async enter() {
        super.enter();

        this.running = true;
        
        // hide eye
        $('#face').style.display = 'none';

        if (this.autoRun) {
            $('#test-label').innerHTML = 'Auto-run photo test';
        }
        else {
            $('#test-label').innerHTML = 'Click to take photo';
        }

        this._setShowBackground(false, '');

        // reset
        this.autoRunAttempts = 0;
        this.autoRunSuccesses = 0;

        if (this.autoRun) {
            this.myIntervalId = setInterval(() => {
                if (this.autoRunAttempts < 20) {
                    this._takePhoto();
                    const failures = this.autoRunAttempts - this.autoRunSuccesses;

                    this.autoRunAttempts++;
                    $('#test-label').innerHTML = ('Auto-run attempts: ' + this.autoRunAttempts + '/20');

                    if (failures >= 0) {
                        $('#test-label2').innerHTML = ('(' + failures + ' failures)');
                    }
                }
                else {
                    this.stop();
                }
            }, 3000);
        }

    }

    stop() {
        if (this.autoRun && (this.myIntervalId !== undefined)) {
            clearInterval(this.myIntervalId);

            $('#test-label').innerHTML = 'Click to take photo';
            let failures = this.autoRunAttempts - this.autoRunSuccesses;
            $('#test-label2').innerHTML = ('(Last auto-run: ' + this.autoRunAttempts + ' attempts and ' + failures + ' failures)');

            // clear everything.
            this.myIntervalId = null;
            this.autoRunAttempts = 0;
            this.autoRunSuccesses = 0;
            this.autoRun = false;

            this._setShowBackground(false, '');
        }
    }

    exit() {
        super.exit();

        this.stop(); // stop if we are in middle of auto-running

        // clear text
        $('#test-label').innerHTML = '';
        $('#test-label2').innerHTML = '';

        // reset background image
        this._setShowBackground(false, '');

        // show eye
        $('#face').style.display = 'block';

        this.running = false;
    }

    click(event) {
        super.click(event);

        this._takePhoto();
    }

    _takePhoto() {
        this._setShowBackground(false, '');

        if (!this.autoRun) {
            // clear it if user clicked manually
            $('#test-label2').innerHTML = '';
        }

        // just do full (aka SNAP) image for this test with no distortion
        media.takePhoto((error, data) => {
            if (!this.running) {
                return;
            }

            const bkg = $('#background');
            if (error) {
                $('#test-label').innerHTML = error;
                this._setShowBackground(true, 'assets/off-air.gif');
            }
            else {
                this._log.info('photo taken');
                this._setShowBackground(true, data.url);

                if (this.autoRun) {
                    this.autoRunSuccesses++;
                    const failures = this.autoRunAttempts - this.autoRunSuccesses;
                    if (failures >= 0) {
                        $('#test-label2').innerHTML = ('(' + failures + ' failures)');
                    }
                }
            }
        });
    }

    _setShowBackground(show, source) {
        const bkg = $('#background');
        bkg.style.display = (show ? 'block' : 'none');
        bkg.src = source;
    }
}

export default PhotoTest;
