import BaseTest from '../BaseTest';
import jibo = require('jibo');
import $ from '../utils/querySelector';

/*
* OTA diagnostic test
* */
class OTATest extends BaseTest {
    public exiting:boolean;
    public downloading:boolean;
    public installing:boolean;
    public dirty:boolean;
    private _haveCredentials:boolean;

    constructor(testName:string) {
        super(testName);
        this._haveCredentials = false;
        this.downloading = false;
        this.installing = false;
        this.dirty = false;
    }

    async enter() {
        super.enter();

        $('#test-label').innerHTML = 'No updates available';
        $('#test-label2').innerHTML = '';
        this.exiting = false;

        // get credentials
        jibo.systemManager.getCredentials((error) => {
            if (error) {
                this._log.info('No credentials set? ' + error);
                $('#test-label').innerHTML = 'Cannot OTA. Get credentials on your robot first!';
            }
            else {
                this._haveCredentials = true;
            }
        });
    }

    exit() {
        super.exit();

        $('#test-label').innerHTML = '';
        $('#test-label2').innerHTML = '';

        this.exiting = true;
    }

    click(event) {
        super.click(event);

        if (this.exiting ||         // are we in middle of exiting test?
            this.downloading ||     // are we in the middle of downloading an update?
            this.installing ||      // are we in the middle of installing an update?
            !this._haveCredentials)  // do we have credentials?
        {
            return; // nope
        }

        jibo.systemManager.checkForUpdates((error, updateList) => {
            if (error) {
                this._log.info('Error during checkForUpdates: ' + error);
            }
            else {
                // get the next item that is available for download
                let downloadData = { 'ids' : []};
                let installData = { 'ids': []};
                for (let i = 0; i < updateList.length; i++) {
                    if (updateList[i].downloaded) {
                        installData.ids.push(updateList[i].id);
                    }
                    else {
                        // then we've found one
                        downloadData.ids.push(updateList[i].id);
                        break;  // stop at first one we need to download
                    }
                }

                // any thing to download still?
                if (downloadData.ids.length > 0) {
                    this.downloading = true;
                    $('#test-label2').innerHTML = 'Downloading...';
                    jibo.systemManager.downloadUpdates(downloadData, (error, data?) => {
                        this._downloadCB(error, data);
                    });
                }
                else if (installData.ids.length > 0){
                    this.installing = true;
                    let label = $('#test-label2');
                    label.innerHTML = 'Installing...see you on the other side (hopefully)!';
                    // check if we should be installing instead?
                    jibo.systemManager.installUpdates(installData, (error) => {
                        if (error) {
                            label.innerHTML = 'Error installing! (' + error + ')';
                        }
                    });
                }
            }
        });
    }

    _downloadCB(error, data) {
        if (!this.downloading) {
            return; //nothing to display
        }

        let progressMsg = '';

        if (error) {
            progressMsg = 'Download error: ' + error;
            this.downloading = false;
        }
        else if (data) {
            if (data.status === 'finished') {
                progressMsg = 'Download finished!';

                this.downloading = false;
                this.dirty = true;
            }
            else if (data.status === 'downloading') {
                progressMsg = 'Downloading (' + Math.round((data.received/data.length * 100)) + '%)';

                this.downloading = true; // still true!
            }
            else if (data.status === 'failed') {
                progressMsg = 'Download failed: ' + data.reason;

                this.downloading = false;
                this.dirty = true;
            }
        }

        if (progressMsg.length > 0) {
            this._log.info(progressMsg);
        }

        $('#test-label2').innerHTML = progressMsg;
    }

    _updateProgress(updateList) {
        let downloaded = 0;
        let available = 0;
        if (updateList && updateList.length > 0) {
            available = updateList.length;
        }

        // check what has already been downloaded
        for (let i = 0; i < available; i++) {
            if (updateList[i].downloaded) {
                downloaded++;
            }
        }

        let header = 'OTAs (downloaded/available): ' + downloaded + '/' + available;
        $('#test-label').innerHTML = header;

        if (available > 0) {
            if (downloaded < available) {
                $('#test-label2').innerHTML = 'Click to download';
            }
            else if (downloaded === available) {
                $('#test-label2').innerHTML = 'Click to install';
            }
        }
    }


    update() {
        if (this.dirty && !this.exiting) {
            this.dirty = false;

            // update download details if needed
            jibo.systemManager.checkForUpdates((error, updateList) => {
                if (error) {
                    this._log.info('Error during checkForUpdates: ' + error);
                }
                else {
                    this._updateProgress(updateList);
                }
            });
        }
    }
}

export default OTATest;
